# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request
from elasticsearch import Elasticsearch
app = Flask(__name__)
es = Elasticsearch([{'host': 'localhost', 'port': 9200}]) # assuming your es runs on localhost and port 9200

@app.route('/api/search', methods=['GET'])
def search():
    keyword = request.args.get('q')
    
    if not keyword:
        return {"error": "Missing query parameter 'q'"}, 400
        
    res = es.search(index="product", body={"query": { "match": { "title": keyword }}}) # assuming you have product index with a field named title
    
    products = [hit['_source'] for hit in res['hits']['hits']]
        
    return {"products": products}, 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000) # running on port 5000